import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';
import { baiDangAPI, danhGiaAPI, nguoiDungAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './HoSoCaNhan.css';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

export default function HoSoCaNhan() {
  const { user, layThongTinToi } = useAuthStore();
  const [editing, setEditing] = useState(false);
  const [form, setForm] = useState({ hoTen: '', soDienThoai: '' });
  const [saving, setSaving] = useState(false);
  const [danhGias, setDanhGias] = useState([]);
  const [loadingDanhGia, setLoadingDanhGia] = useState(true);
  const [baiDangCuaToi, setBaiDangCuaToi] = useState([]);
  const [loadingBaiDang, setLoadingBaiDang] = useState(true);
  const [deletingBaiDangId, setDeletingBaiDangId] = useState(null);

  useEffect(() => {
    setForm({
      hoTen: user?.hoTen || '',
      soDienThoai: user?.soDienThoai || '',
    });
  }, [user]);

  useEffect(() => {
    let active = true;

    danhGiaAPI.layNhanDuoc()
      .then(res => {
        if (active) {
          setDanhGias(res.data.data || []);
        }
      })
      .catch(() => {})
      .finally(() => {
        if (active) {
          setLoadingDanhGia(false);
        }
      });

    return () => {
      active = false;
    };
  }, []);

  useEffect(() => {
    let active = true;

    baiDangAPI.layBaiDangCuaToi()
      .then(res => {
        if (active) {
          setBaiDangCuaToi(res.data.data || []);
        }
      })
      .catch(() => {
        if (active) {
          setBaiDangCuaToi([]);
        }
      })
      .finally(() => {
        if (active) {
          setLoadingBaiDang(false);
        }
      });

    return () => {
      active = false;
    };
  }, []);

  const handleSave = async () => {
    setSaving(true);
    try {
      await nguoiDungAPI.capNhat(form);
      await layThongTinToi();
      toast.success('Cập nhật thành công!');
      setEditing(false);
    } catch {
      toast.error('Cập nhật thất bại');
    }
    setSaving(false);
  };

  const handleAvatarChange = async e => {
    const file = e.target.files[0];
    if (!file) return;

    const fd = new FormData();
    fd.append('file', file);

    try {
      await nguoiDungAPI.uploadAvatar(fd);
      await layThongTinToi();
      toast.success('Cập nhật ảnh đại diện thành công!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Upload thất bại');
    }
  };

  const handleDeleteBaiDang = async maBaiDang => {
    if (!window.confirm('Bạn có chắc muốn xóa bài đăng này không?')) return;

    setDeletingBaiDangId(maBaiDang);
    try {
      await baiDangAPI.xoa(maBaiDang);
      setBaiDangCuaToi(current => current.filter(item => item.maBaiDang !== maBaiDang));
      toast.success('Đã xóa bài đăng');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xóa bài đăng thất bại');
    }
    setDeletingBaiDangId(null);
  };

  if (!user) return <div className="spinner" />;

  const danhGiaHienThi = [...danhGias]
    .sort((a, b) => new Date(b.ngayDanhGia || 0) - new Date(a.ngayDanhGia || 0))
    .slice(0, 5);

  const baiDangHienThi = [...baiDangCuaToi]
    .sort((a, b) => new Date(b.ngayDang || 0) - new Date(a.ngayDang || 0));

  return (
    <div className="container page-wrapper">
      <div className="hoso-layout">
        <div className="card profile-card">
          <div className="card-body" style={{ textAlign: 'center' }}>
            <div className="avatar-upload">
              <img
                src={user.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(user.hoTen)}&background=12355B&color=fff&size=120`}
                className="avatar avatar-xl"
                alt=""
              />
              <label htmlFor="avatar-input" className="avatar-edit-btn" title="Đổi ảnh">✏️</label>
              <input id="avatar-input" type="file" accept="image/*" hidden onChange={handleAvatarChange} />
            </div>
            <h2 style={{ marginTop: 16, fontWeight: 800 }}>{user.hoTen}</h2>
            <div style={{ marginTop: 12, fontSize: 14, color: 'var(--text-muted)' }}>
              Trang công khai của bạn chỉ hiển thị cho user khác khi họ bấm vào tên hoặc avatar của bạn.
            </div>

            {user.xacThuc ? (
              <span className="badge badge-success" style={{ marginTop: 8 }}>Đã xác thực CCCD</span>
            ) : (
              <Link
                to="/xac-thuc"
                className="badge badge-warning"
                style={{ marginTop: 8, cursor: 'pointer', textDecoration: 'none' }}
              >
                Chưa xác thực - Xác thực ngay
              </Link>
            )}

            <div style={{ marginTop: 14 }}>
              {user.diemDanhGia ? (
                <div className="stars">
                  {'★'.repeat(Math.round(user.diemDanhGia))}
                  {'☆'.repeat(5 - Math.round(user.diemDanhGia))}
                  <span style={{ fontSize: 14, color: 'var(--text-muted)', marginLeft: 6 }}>
                    {user.diemDanhGia.toFixed(1)} / 5
                  </span>
                </div>
              ) : (
                <div style={{ color: 'var(--text-muted)', fontSize: 14 }}>Chưa có đánh giá nào</div>
              )}
            </div>

            <div style={{ marginTop: 20, padding: '16px 0', borderTop: '1px solid var(--border)' }}>
              <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>Số dư ví</div>
              <div style={{ fontSize: 24, fontWeight: 800, color: 'var(--primary)' }}>{fmt(user.soDuVi)}</div>
              <div className="profile-wallet-actions">
                <Link to="/thanh-toan" className="btn btn-outline btn-sm">Nạp tiền</Link>
                <Link to="/hoa-don" className="btn btn-outline btn-sm">Hóa đơn</Link>
              </div>
            </div>
          </div>
        </div>

        <div>
          <div className="card">
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span>Thông tin cá nhân</span>
              {!editing ? (
                <button className="btn btn-outline btn-sm" onClick={() => setEditing(true)}>Chỉnh sửa</button>
              ) : (
                <div style={{ display: 'flex', gap: 8 }}>
                  <button className="btn btn-primary btn-sm" onClick={handleSave} disabled={saving}>
                    {saving ? 'Đang lưu...' : 'Lưu'}
                  </button>
                  <button className="btn btn-secondary btn-sm" onClick={() => setEditing(false)}>Hủy</button>
                </div>
              )}
            </div>
            <div className="card-body">
              {editing ? (
                <>
                  <div className="form-group">
                    <label className="form-label">Họ và tên</label>
                    <input
                      className="form-control"
                      value={form.hoTen}
                      onChange={e => setForm(current => ({ ...current, hoTen: e.target.value }))}
                    />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Số điện thoại</label>
                    <input
                      className="form-control"
                      value={form.soDienThoai}
                      onChange={e => setForm(current => ({ ...current, soDienThoai: e.target.value }))}
                    />
                  </div>
                </>
              ) : (
                <div>
                  {[
                    ['Họ tên', user.hoTen],
                    ['Email', user.email],
                    ['Điện thoại', user.soDienThoai || 'Chưa cập nhật'],
                    ['Ngày tham gia', user.ngayTao ? new Date(user.ngayTao).toLocaleDateString('vi-VN') : ''],
                  ].map(([label, value]) => (
                    <div key={label} className="info-row">
                      <span style={{ color: 'var(--text-muted)' }}>{label}</span>
                      <strong>{value}</strong>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="card" style={{ marginTop: 20 }}>
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span>Đánh giá nhận được</span>
              <Link to="/danh-gia" className="btn btn-outline btn-sm">Quản lý đánh giá</Link>
            </div>
            <div className="card-body">
              {loadingDanhGia ? (
                <div style={{ color: 'var(--text-muted)' }}>Đang tải đánh giá...</div>
              ) : danhGiaHienThi.length === 0 ? (
                <div className="review-empty">
                  Hồ sơ hiện chưa có đánh giá nào dành cho bạn.
                </div>
              ) : (
                <div className="review-list">
                  {danhGiaHienThi.map(dg => (
                    <div key={dg.maDanhGia} className="review-item">
                      <div className="review-top">
                        <strong>{dg.tenNguoiDanhGia || 'Người dùng ẩn danh'}</strong>
                        <span className="stars">{'★'.repeat(dg.soSao)}{'☆'.repeat(5 - dg.soSao)}</span>
                      </div>
                      <div style={{ color: 'var(--text-muted)', marginTop: 6 }}>
                        {dg.moTa || 'Không có nhận xét chi tiết'}
                      </div>
                      <div className="review-date">
                        {dg.ngayDanhGia ? new Date(dg.ngayDanhGia).toLocaleDateString('vi-VN') : ''}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="card" style={{ marginTop: 20 }}>
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span>Quản lý bài đăng</span>
              <Link to="/tao-bai-dang" className="btn btn-outline btn-sm">Đăng bài mới</Link>
            </div>
            <div className="card-body">
              {loadingBaiDang ? (
                <div style={{ color: 'var(--text-muted)' }}>Đang tải danh sách bài đăng...</div>
              ) : baiDangHienThi.length === 0 ? (
                <div className="review-empty">
                  Bạn chưa có bài đăng nào. Hãy tạo bài đăng để tìm bạn ở ghép.
                </div>
              ) : (
                <div className="post-manage-list">
                  {baiDangHienThi.map(baiDang => (
                    <div key={baiDang.maBaiDang} className="post-manage-item">
                      <div className="post-manage-top">
                        <div>
                          <div className="post-manage-title">{baiDang.moTa}</div>
                          <div className="post-manage-meta">
                            <span>{fmt(baiDang.giaTien)}/tháng</span>
                            <span>{baiDang.diaChi}</span>
                            <span>{baiDang.ngayDang ? new Date(baiDang.ngayDang).toLocaleDateString('vi-VN') : ''}</span>
                          </div>
                        </div>
                        <span
                          className={`badge ${
                            baiDang.trangThai === 'Dang'
                              ? 'badge-success'
                              : baiDang.trangThai === 'Tam dung'
                                ? 'badge-warning'
                                : 'badge-gray'
                          }`}
                        >
                          {baiDang.trangThai || 'Dang'}
                        </span>
                      </div>

                      {baiDang.noiDung && (
                        <div className="post-manage-content">{baiDang.noiDung}</div>
                      )}

                      <div className="post-manage-actions">
                        <Link to={`/bai-dang/${baiDang.maBaiDang}`} className="btn btn-outline btn-sm">Xem chi tiết</Link>
                        <Link to={`/bai-dang/${baiDang.maBaiDang}/chinh-sua`} className="btn btn-secondary btn-sm">Chỉnh sửa</Link>
                        <button
                          type="button"
                          className="btn btn-danger btn-sm"
                          onClick={() => handleDeleteBaiDang(baiDang.maBaiDang)}
                          disabled={deletingBaiDangId === baiDang.maBaiDang}
                        >
                          {deletingBaiDangId === baiDang.maBaiDang ? 'Đang xóa...' : 'Xóa'}
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="card" style={{ marginTop: 20 }}>
            <div className="card-header">Hành động nhanh</div>
            <div className="card-body">
              <div className="quick-actions">
                {[
                  ['/quan-ly-phong', '🏠', 'Quản lý phòng'],
                  ['/tao-bai-dang', '📝', 'Đăng bài'],
                  ['/yeu-cau', '📋', 'Yêu cầu của tôi'],
                  ['/thanh-toan', '💰', 'Ví tiền'],
                  ['/hoa-don', '📄', 'Hóa đơn của tôi'],
                  ['/tam-tru', '📑', 'Phiếu tạm trú'],
                  ['/danh-gia', '⭐', 'Đánh giá'],
                  ['/xac-thuc', '🔐', 'Xác thực CCCD'],
                ].map(([to, icon, label]) => (
                  <Link key={to} to={to} className="quick-action-btn">
                    <span>{icon}</span>
                    <span>{label}</span>
                  </Link>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
